#!/usr/bin/env python3
"""
Stock Reaction Helper — Earnings Analysis Agent

Pulls post-earnings price data from Yahoo Finance and writes stock_reaction.json
in the format expected by the Earnings Analysis Agent.

Usage:
    python stock_reaction_helper.py XYZ 2026-04-23 AMC --sector-etf XLV
    python stock_reaction_helper.py XYZ 2026-04-15 BMO --sector-etf XLV --implied-move 5.2

Arguments:
    TICKER          Stock ticker (e.g., XYZ)
    EARNINGS_DATE   Earnings date in YYYY-MM-DD format
    REPORT_TIME     BMO (before market open) or AMC (after market close)

Options:
    --sector-etf    Sector ETF ticker for relative comparison (e.g., XLV, XLI, SOXX)
    --implied-move  Implied move from options (percent). Must be manually provided
                    — this script cannot reliably scrape options data.
    --output-dir    Output directory. Defaults to workspace/{TICKER}/
    --append        Append to existing stock_reaction.json instead of overwriting

Requires: yfinance (pip install yfinance)
"""

import argparse
import json
import os
import sys
from datetime import datetime, timedelta
from pathlib import Path

try:
    import yfinance as yf
except ImportError:
    print("ERROR: yfinance not installed. Run: pip install yfinance")
    sys.exit(1)


def get_trading_day_before(date, ticker_data):
    """Find the last trading day on or before the given date."""
    target = date
    for _ in range(5):  # look back up to 5 calendar days
        day_data = ticker_data.loc[ticker_data.index.date == target.date()]
        if not day_data.empty:
            return day_data
        target -= timedelta(days=1)
    return None


def get_trading_day_after(date, ticker_data):
    """Find the first trading day on or after the given date."""
    target = date
    for _ in range(5):  # look forward up to 5 calendar days
        day_data = ticker_data.loc[ticker_data.index.date == target.date()]
        if not day_data.empty:
            return day_data
        target += timedelta(days=1)
    return None


def fetch_reaction_data(ticker: str, earnings_date: str, report_time: str,
                        sector_etf: str = None, implied_move: float = None,
                        notes: str = None) -> dict:
    """
    Fetch price data around earnings and compute reaction metrics.

    For AMC (after market close):
        - pre_earnings_close = close on earnings_date
        - next_day = first trading day after earnings_date
    For BMO (before market open):
        - pre_earnings_close = close on day before earnings_date
        - next_day = earnings_date itself (market reacts at open)
    """
    edate = datetime.strptime(earnings_date, "%Y-%m-%d")

    # Fetch enough data to find trading days around the event
    start = edate - timedelta(days=10)
    end = edate + timedelta(days=10)

    print(f"Fetching {ticker} data from {start.date()} to {end.date()}...")
    stock = yf.download(ticker, start=start.strftime("%Y-%m-%d"),
                        end=end.strftime("%Y-%m-%d"), progress=False)

    if stock.empty:
        print(f"ERROR: No price data returned for {ticker}. Check ticker and date range.")
        sys.exit(1)

    # Flatten multi-level columns if present (yfinance >= 0.2.31)
    if hasattr(stock.columns, 'levels') and len(stock.columns.levels) > 1:
        stock.columns = stock.columns.get_level_values(0)

    result = {
        "ticker": ticker.upper(),
        "earnings_date": earnings_date,
        "report_time": report_time.upper(),
        "pre_earnings_close": None,
        "afterhours_move_pct": None,
        "next_day_open": None,
        "next_day_close": None,
        "next_day_move_pct": None,
        "sector_etf": sector_etf,
        "sector_etf_next_day_move_pct": None,
        "spy_next_day_move_pct": None,
        "implied_move_options": implied_move,
        "notes": notes if notes else f"Auto-generated by stock_reaction_helper.py on {datetime.now().strftime('%Y-%m-%d %H:%M')}"
    }

    if report_time.upper() == "AMC":
        # Pre-earnings close = close on earnings date
        pre_day = get_trading_day_before(edate, stock)
        next_day = get_trading_day_after(edate + timedelta(days=1), stock)
    elif report_time.upper() == "BMO":
        # Pre-earnings close = close on day before earnings date
        pre_day = get_trading_day_before(edate - timedelta(days=1), stock)
        next_day = get_trading_day_after(edate, stock)
    else:
        print(f"ERROR: report_time must be BMO or AMC, got '{report_time}'")
        sys.exit(1)

    if pre_day is None or next_day is None:
        print("WARNING: Could not find trading days around earnings date.")
        print("  This may mean earnings haven't happened yet or the date is wrong.")
        print("  Writing partial data — fill in missing fields manually.")
        return result

    pre_close = float(pre_day["Close"].iloc[-1])
    next_open = float(next_day["Open"].iloc[0])
    next_close = float(next_day["Close"].iloc[0])

    result["pre_earnings_close"] = round(pre_close, 2)
    result["next_day_open"] = round(next_open, 2)
    result["next_day_close"] = round(next_close, 2)
    result["next_day_move_pct"] = round((next_close - pre_close) / pre_close * 100, 2)

    # Afterhours move approximated as gap from pre-close to next-day open
    result["afterhours_move_pct"] = round((next_open - pre_close) / pre_close * 100, 2)

    # Fetch SPY for market context
    print("Fetching SPY data for market context...")
    spy = yf.download("SPY", start=start.strftime("%Y-%m-%d"),
                      end=end.strftime("%Y-%m-%d"), progress=False)
    if hasattr(spy.columns, 'levels') and len(spy.columns.levels) > 1:
        spy.columns = spy.columns.get_level_values(0)

    if not spy.empty:
        if report_time.upper() == "AMC":
            spy_pre = get_trading_day_before(edate, spy)
            spy_next = get_trading_day_after(edate + timedelta(days=1), spy)
        else:
            spy_pre = get_trading_day_before(edate - timedelta(days=1), spy)
            spy_next = get_trading_day_after(edate, spy)

        if spy_pre is not None and spy_next is not None:
            spy_pre_close = float(spy_pre["Close"].iloc[-1])
            spy_next_close = float(spy_next["Close"].iloc[0])
            result["spy_next_day_move_pct"] = round(
                (spy_next_close - spy_pre_close) / spy_pre_close * 100, 2
            )

    # Fetch sector ETF if provided
    if sector_etf:
        print(f"Fetching {sector_etf} data for sector context...")
        etf = yf.download(sector_etf, start=start.strftime("%Y-%m-%d"),
                          end=end.strftime("%Y-%m-%d"), progress=False)
        if hasattr(etf.columns, 'levels') and len(etf.columns.levels) > 1:
            etf.columns = etf.columns.get_level_values(0)

        if not etf.empty:
            if report_time.upper() == "AMC":
                etf_pre = get_trading_day_before(edate, etf)
                etf_next = get_trading_day_after(edate + timedelta(days=1), etf)
            else:
                etf_pre = get_trading_day_before(edate - timedelta(days=1), etf)
                etf_next = get_trading_day_after(edate, etf)

            if etf_pre is not None and etf_next is not None:
                etf_pre_close = float(etf_pre["Close"].iloc[-1])
                etf_next_close = float(etf_next["Close"].iloc[0])
                result["sector_etf_next_day_move_pct"] = round(
                    (etf_next_close - etf_pre_close) / etf_pre_close * 100, 2
                )

    return result


def main():
    parser = argparse.ArgumentParser(
        description="Generate stock_reaction.json for the Earnings Analysis Agent"
    )
    parser.add_argument("ticker", help="Stock ticker (e.g., XYZ)")
    parser.add_argument("earnings_date", help="Earnings date (YYYY-MM-DD)")
    parser.add_argument("report_time", choices=["BMO", "AMC", "bmo", "amc"],
                        help="BMO (before market open) or AMC (after market close)")
    parser.add_argument("--sector-etf", default=None,
                        help="Sector ETF ticker (e.g., XLV, XLI)")
    parser.add_argument("--implied-move", type=float, default=None,
                        help="Implied move from options (percent). Manual input required.")
    parser.add_argument("--output-dir", default=None,
                        help="Output directory. Defaults to workspace/{TICKER}/")
    parser.add_argument("--notes", default=None,
                        help="Optional analyst notes (free text). If omitted, auto-generated timestamp is used.")
    parser.add_argument("--append", action="store_true",
                        help="Append to existing stock_reaction.json")

    args = parser.parse_args()

    reaction = fetch_reaction_data(
        ticker=args.ticker,
        earnings_date=args.earnings_date,
        report_time=args.report_time,
        sector_etf=args.sector_etf,
        implied_move=args.implied_move,
        notes=args.notes,
    )

    # Determine output path
    if args.output_dir:
        out_dir = Path(args.output_dir)
    else:
        out_dir = Path(f"workspace/{args.ticker.upper()}")

    out_dir.mkdir(parents=True, exist_ok=True)
    out_file = out_dir / "stock_reaction.json"

    # Handle append mode
    if args.append and out_file.exists():
        with open(out_file, "r") as f:
            existing = json.load(f)
        if isinstance(existing, list):
            existing.append(reaction)
        else:
            existing = [existing, reaction]
        data = existing
    else:
        data = [reaction]

    with open(out_file, "w") as f:
        json.dump(data, f, indent=2)

    print(f"\nWritten to: {out_file}")
    print(f"\nReaction summary:")
    print(f"  Pre-earnings close: ${reaction['pre_earnings_close']}")
    print(f"  Next-day close:     ${reaction['next_day_close']}")
    print(f"  Next-day move:      {reaction['next_day_move_pct']}%")
    print(f"  SPY move:           {reaction['spy_next_day_move_pct']}%")
    if reaction['sector_etf_next_day_move_pct'] is not None:
        print(f"  {reaction['sector_etf']} move:  {reaction['sector_etf_next_day_move_pct']}%")
    if reaction['implied_move_options'] is not None:
        print(f"  Implied move:       {reaction['implied_move_options']}%")
    else:
        print(f"  Implied move:       NOT PROVIDED (pass --implied-move)")

    # Validation warnings
    warnings = []
    if reaction["pre_earnings_close"] is None:
        warnings.append("Missing pre-earnings close — check date and ticker")
    if reaction["implied_move_options"] is None:
        warnings.append("No implied move provided — algorithmic reaction comparison will be incomplete")
    if reaction["sector_etf"] is None:
        warnings.append("No sector ETF specified — sector-relative comparison unavailable")

    if warnings:
        print(f"\nWarnings:")
        for w in warnings:
            print(f"  ⚠️  {w}")


if __name__ == "__main__":
    main()
